// visitorRegistry maps visitor handle IDs to active Visitor instances.
// CGo does not allow passing Go function values as C function pointers;
// we use a numeric ID (stored in user_data) to look up the Visitor at callback time.
var (
	visitorRegistry sync.Map
	visitorIDCounter atomic.Uint64
)

func registerVisitor(v Visitor) uintptr {
	id := uintptr(visitorIDCounter.Add(1))
	visitorRegistry.Store(id, v)
	return id
}

func unregisterVisitor(id uintptr) {
	visitorRegistry.Delete(id)
}

func lookupVisitor(id uintptr) (Visitor, bool) {
	v, ok := visitorRegistry.Load(id)
	if !ok {
		return nil, false
	}
	return v.(Visitor), true
}

func decodeNodeContext(c *C.HTMHtmNodeContext) NodeContext {
	ctx := NodeContext{
		NodeType:      int32(c.node_type),
		TagName:       C.GoString(c.tag_name),
		Depth:         uint(c.depth),
		IndexInParent: uint(c.index_in_parent),
		IsInline:      c.is_inline != 0,
	}
	if c.parent_tag != nil {
		s := C.GoString(c.parent_tag)
		ctx.ParentTag = &s
	}
	return ctx
}

func encodeVisitResult(r VisitResult, outCustom **C.char, outLen *C.size_t) C.int32_t {
	if (r.Code == 3 || r.Code == 4) && r.Custom != nil {
		cs := C.CString(*r.Custom)
		*outCustom = cs
		*outLen = C.size_t(len(*r.Custom))
	}
	return C.int32_t(r.Code)
}

func optGoString(p *C.char) *string {
	if p == nil {
		return nil
	}
	s := C.GoString(p)
	return &s
}

func decodeCells(cells **C.char, count C.size_t) []string {
	n := int(count)
	if n == 0 {
		return nil
	}
	ptrs := (*[1 << 28]*C.char)(unsafe.Pointer(cells))[:n:n]
	sl := make([]string, n)
	for i, p := range ptrs {
		sl[i] = C.GoString(p)
	}
	return sl
}

